module RefModule (clk, rst, en, count);
   input clk, rst, en;
   output [3:0] count;

   reg [3:0] count;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
    if (rst) 
    begin
        count <= 0;
    end 
    else if (en) 
    begin
        count <= count + 1;
    end
end

endmodule
